          <Pressable key={t.id} style={styles.tab} onPress={() => onChange(t.id)} hitSlop={6}>
            {on && <View style={styles.tabGlow} />}
            <Icon id={t.id} active={on} />
            <Text style={[styles.tabLabel, on && { color: N.candle }]}>{t.label}</Text>
          </Pressable>
        );
      })}
    </View>
  );
}

